+function trimLines(lines: string[], trimLeadingWhitespace: boolean): string[] {
+  if (!trimLeadingWhitespace) return lines;
+  return lines.map((line, index) => (index === 0 ? line : line.replace(/^\\s+/, '')));
+}
+
+function isInternal(line: string, mode: StripInternalFrames): boolean {
+  const node = mode === 'node' || mode === 'node_and_superjson';
+  const superjson = mode === 'superjson' || mode === 'node_and_superjson';
+  return (
+    (node && line.includes('node:internal')) ||
+    (superjson && /src\\/(?:transformer|plainer|index)\\.ts/.test(line))
