+
+function redactLine(line: string, mode: RedactPaths): string {
+  if (mode === 'none') return line;
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/');
+    return line.replace(new RegExp(cwd.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&'), 'g'), '');
