+function serializeError(
+  error: Error,
+  superJson: SuperJSON,
+  annotation: 'Error' | 'Error/stack' | 'Error/frames'
+): Record<string, any> {
+  const options = superJson.errorStackOptions;
+  const shouldProcess =
+    !!options && options.mode !== 'off' && superJson.shouldProcessErrorStack(error);
+  const baseError: Record<string, any> = {
+    name: error.name,
+    message:
+      shouldProcess && options!.sanitizeMessage
+        ? (awaitableSanitize(error.message))
+        : error.message,
+  };
+  const depth = superJson.getErrorCauseDepth(error);
+  superJson.markErrorCause(error);
+
+  if (!options) {
+    if ('cause' in error) baseError.cause = (error as any).cause;
+  } else if (
+    'cause' in error &&
+    isError((error as any).cause) &&
+    superJson.shouldIncludeErrorCause(error, depth) &&
+    !superJson.markErrorCause((error as any).cause)
+  ) {
+    // A repeated or circular cause is deliberately omitted.
+  } else if (
+    'cause' in error &&
+    isError((error as any).cause) &&
+    superJson.shouldIncludeErrorCause(error, depth)
