+    const cause = (error as any).cause as Error;
+    // markErrorCause above is only used to check cycles; allow the walker to serialize it.
+    superJson.setErrorCauseDepth(cause, depth + 1);
+    baseError.cause = cause;
+  }
+
+  if (typeof (error as any).errors !== 'undefined') {
+    baseError.errors = (error as any).errors;
+  }
+
+  superJson.allowedErrorProps.forEach(prop => {
+    if (options && (prop === 'stack' || prop === 'stackFrames')) return;
+    baseError[prop] = (error as any)[prop];
